        if (status == null || !status.getValue().equals(Response.STATUS_SUCCESS)) { // Check the response status
            System.out.println("The received SAML Response is not successful: " + status);
            return;
        }
        
        Assertion assertion = nameIDMappingResponse.getAssertions().iterator().next(); 
        Subject subject = assertion.getSubjects().iterator().next(); // Extract user attributes from the assertions
        NameID nameID = subject.getNameId();
        
        System.out.println("User ID: " + nameID.getValue());

